erse CDF of truncated exponential", "-      # CDF: F(x) = (exp(b*x) - exp(b*lo)) / (exp(b*hi) - exp(b*lo))", "-      u <- runif(1)", "-      # x = log(exp(b*lo) + u * (exp(b*hi) - exp(b*lo))) / b", "-      # Numerically stable version:", "-      log_lo <- b * lo", "-      log_hi <- b * hi", "-      if (b > 0) {", "-        samples[i] <- (log_lo + log(1 + u * (exp(log_hi - log_lo) - 1))) / b", "-      } else {", "-        samples[i] <- (log_hi + log(1 + (1 - u) * (exp(log_lo - log_hi) - 1))) / b", "-      }", "+      # Both finite: inverse CDF of truncated exponential", "+      log_lo <- m[j] * lo", "+      log_hi <- m[j] * hi", "+      # CDF: F(x) = (exp(m*x) - exp(m*lo)) / (exp(m*hi) - exp(m*lo))", "+      # Inverse: x = log(exp(m*lo) + u*(exp(m*hi) - exp(m*lo))) / m", "+      log_max <- max(log_lo, log_hi)", "+      exp_lo <- exp(log_lo - log_max)", "+      exp_hi <- exp(log_hi - log_max)", "+      samples[i] <- (log_max + log(exp_lo + u * (exp_hi - exp_lo))) / m[j]", "     }", "   }", "   return(samples)", " }", " ", " #' Choose initial abscissae for the ARS algorithm", "+#' Ensures at least 3 points with positive density, and that", "+#' boundary slopes are compatible with infinite domains.", " #' @param lb lower bound", " #' @param ub upper bound", " #' @param f density function", "-#' @param n_init number of initial points (default 5)", "+#' @param n_init number of initial points (default 5, minimum 3)", " #' @return vector of initial abscissae", "-choose_initial_abscissae <- function(lb, ub, f, n_init = 5) {", "-  # Handle infinite bounds", "+choose_initial_abscissae <- function(lb, ub, f, n_init = 20) {", "+  n_init <- max(n_init, 5)", "+", "+  # Generate candidate points", "   if (is.finite(lb) && is.finite(ub)) {", "-    # Both finite: space evenly", "-    pts <- seq(lb + (ub - lb) * 0.05, ub - (ub - lb) * 0.05, length.out = n_init)", "+    margin <- (ub - lb) * 0.02", "+    pts <- seq(lb + margin, ub - margin, length.out = n_init)", "   } else if (is.fini