###############################################################################
# Adaptive Rejection Sampling (ARS)
# Based on Gilks, W.R. & Wild, P. (1992)
# "Adaptive Rejection Sampling for Gibbs Sampling"
# Journal of the Royal Statistical Society: Series C, 41(2), 337-348.
#
# Derivative-free implementation using secant-based upper hull construction.
###############################################################################

# --- Auxiliary / Module Functions ---

#' Evaluate the log of a density function safely
#' @param f density function (possibly unnormalized)
#' @param x point(s) at which to evaluate
#' @return log(f(x)), with protection against f(x) <= 0
eval_log_density <- function(f, x) {
  fx <- f(x)
  if (any(is.na(fx) | is.nan(fx))) {
    stop("Density function returned NA/NaN.")
  }
  if (any(fx < 0)) {
    stop("Density function returned negative value.")
  }
  result <- rep(-Inf, length(fx))
  pos <- fx > 0
  result[pos] <- log(fx[pos])
  return(result)
}

#' Check log-concavity at three consecutive abscissae
#' @param abscissae sorted vector of x values
#' @param h_vals corresponding log-density values h(x)
#' @return TRUE if log-concave, else stops with error
check_log_concavity <- function(abscissae, h_vals) {
  n <- length(abscissae)
  if (n < 3) return(TRUE)
  for (i in 1:(n - 2)) {
    x1 <- abscissae[i];   h1 <- h_vals[i]
    x2 <- abscissae[i+1]; h2 <- h_vals[i+1]
    x3 <- abscissae[i+2]; h3 <- h_vals[i+2]
    slope_left  <- (h2 - h1) / (x2 - x1)
    slope_right <- (h3 - h2) / (x3 - x2)
    if (slope_right > slope_left + 1e-10) {
      stop(paste0(
        "Log-concavity violated at x = ", x2,
        ". Left slope = ", round(slope_left, 6),
        ", Right slope = ", round(slope_right, 6),
        ". The density may not be log-concave."
      ))
    }
  }
  return(TRUE)
}

#' Compute the upper hull for the ARS algorithm (derivative-free version)
#'
#' Constructs a piecewise-linear upper envelope of the log-density using
#' the secant slopes between consecutive abscissae.
#'
#' At each interior abscissa x_j (j = 2,...,k-1), the upper hull forms a
#' "tent" with left arm slope s_j and right arm slope s_{j-1}, where
#' s_j = (h_{j+1} - h_j) / (x_{j+1} - x_j).
#'
#' @param abscissae sorted x values (at least 3)
#' @param h_vals corresponding h(x) = log(f(x)) values
#' @param lb lower bound of domain
#' @param ub upper bound of domain
#' @return list with z (breakpoints), seg_slopes, seg_intercepts, n_seg
compute_upper_hull <- function(abscissae, h_vals, lb, ub) {
  k <- length(abscissae)
  if (k < 3) stop("Need at least 3 abscissae for upper hull construction.")

  # Secant slopes
  s <- diff(h_vals) / diff(abscissae)

  # Build segments: each defined by intercept and slope in form u(x) = b + m*x
  # Segments from left to right:
  #   1. x_1: slope s[1] (only arm, extends left)
  #   For j = 2,...,k-1: left arm slope s[j], right arm slope s[j-1]
  #   Last: x_k: slope s[k-1] (only arm, extends right)

  seg_px <- numeric(0)  # reference x
  seg_ph <- numeric(0)  # reference h
  seg_m  <- numeric(0)  # slope

  # First segment
  seg_px <- c(seg_px, abscissae[1])
  seg_ph <- c(seg_ph, h_vals[1])
  seg_m  <- c(seg_m, s[1])

  # Interior points
  for (j in 2:(k-1)) {
    # Left arm
    seg_px <- c(seg_px, abscissae[j])
    seg_ph <- c(seg_ph, h_vals[j])
    seg_m  <- c(seg_m, s[j])
    # Right arm
    seg_px <- c(seg_px, abscissae[j])
    seg_ph <- c(seg_ph, h_vals[j])
    seg_m  <- c(seg_m, s[j-1])
  }

  # Last segment
  seg_px <- c(seg_px, abscissae[k])
  seg_ph <- c(seg_ph, h_vals[k])
  seg_m  <- c(seg_m, s[k-1])

  # Convert to intercept form: u(x) = seg_int + seg_m * x
  seg_int <- seg_ph - seg_m * seg_px

  # Merge consecutive segments that are effectively the same line
  # (happens when log-density is linear, e.g. exponential distribution)
  keep <- rep(TRUE, length(seg_m))
  for (i in 2:length(seg_m)) {
    if (abs(seg_m[i] - seg_m[i-1]) < 1e-12 && abs(seg_int[i] - seg_int[i-1]) < 1e-6) {
      keep[i] <- FALSE
    }
  }
  seg_px <- seg_px[keep]
  seg_ph <- seg_ph[keep]
  seg_m  <- seg_m[keep]
  seg_int <- seg_int[keep]
  n_seg <- length(seg_m)

  # Compute breakpoints between consecutive segments
  if (n_seg == 1) {
    z <- c(lb, ub)
  } else {
    bp <- numeric(n_seg - 1)
    for (i in 1:(n_seg - 1)) {
      if (seg_px[i] == seg_px[i+1]) {
        # Same reference point (left/right arms of a tent)
        bp[i] <- seg_px[i]
      } else if (abs(seg_m[i] - seg_m[i+1]) < 1e-12) {
        # Parallel lines: use midpoint of reference points
        bp[i] <- (seg_px[i] + seg_px[i+1]) / 2
      } else {
        bp[i] <- (seg_int[i+1] - seg_int[i]) / (seg_m[i] - seg_m[i+1])
      }
    }
    # Ensure breakpoints are valid
    bp[is.na(bp) | is.nan(bp)] <- 0
    z <- c(lb, bp, ub)
  }

  return(list(
    z = z,
    seg_slopes = seg_m,
    seg_intercepts = seg_int,
    n_seg = n_seg
  ))
}

#' Evaluate the upper hull at a point x
#' @param x scalar or vector of points
#' @param hull list from compute_upper_hull
#' @return u(x), the upper hull value(s)
eval_upper_hull <- function(x, hull) {
  z <- hull$z
  m <- hull$seg_slopes
  b <- hull$seg_intercepts
  n_seg <- hull$n_seg

  seg_idx <- findInterval(x, z, rightmost.closed = TRUE)
  seg_idx <- pmax(1, pmin(seg_idx, n_seg))

  return(b[seg_idx] + m[seg_idx] * x)
}

#' Evaluate the lower hull (piecewise linear interpolation) at a point x
#' @param x scalar point
#' @param abscissae sorted x values
#' @param h_vals corresponding h(x) values
#' @return l(x). Returns -Inf if outside the range of abscissae.
eval_lower_hull <- function(x, abscissae, h_vals) {
  k <- length(abscissae)
  if (x <= abscissae[1] || x >= abscissae[k]) {
    return(-Inf)
  }
  j <- findInterval(x, abscissae)
  j <- pmax(1, pmin(j, k - 1))
  t <- (x - abscissae[j]) / (abscissae[j+1] - abscissae[j])
  return(h_vals[j] * (1 - t) + h_vals[j+1] * t)
}

#' Sample from the upper hull (piecewise-exponential distribution)
#' @param n number of samples to draw
#' @param hull list from compute_upper_hull
#' @return vector of n samples
sample_upper_hull <- function(n, hull) {
  z <- hull$z
  m <- hull$seg_slopes
  b <- hull$seg_intercepts
  n_seg <- hull$n_seg

  # Compute area under each segment: integral of exp(b + m*x) from z[j] to z[j+1]
  areas <- numeric(n_seg)
  for (j in 1:n_seg) {
    lo <- z[j]
    hi <- z[j + 1]

    if (!is.finite(lo)) {
      if (m[j] <= 0) { areas[j] <- 0; next }
      areas[j] <- exp(b[j] + m[j] * hi) / m[j]
      next
    }
    if (!is.finite(hi)) {
      if (m[j] >= 0) { areas[j] <- 0; next }
      areas[j] <- -exp(b[j] + m[j] * lo) / m[j]
      next
    }

    if (abs(m[j]) < 1e-15) {
      areas[j] <- exp(b[j]) * (hi - lo)
    } else {
      log_hi <- b[j] + m[j] * hi
      log_lo <- b[j] + m[j] * lo
      log_max <- max(log_hi, log_lo)
      areas[j] <- exp(log_max) * (exp(log_hi - log_max) - exp(log_lo - log_max)) / m[j]
    }

    if (is.na(areas[j]) || !is.finite(areas[j]) || areas[j] < 0) {
      areas[j] <- 0
    }
  }

  total_area <- sum(areas)
  if (total_area <= 0 || !is.finite(total_area)) {
    stop("Upper hull has zero or infinite area. Check domain bounds and initial abscissae.")
  }
  probs <- areas / total_area

  # Sample segments according to their areas
  seg_choices <- sample.int(n_seg, size = n, replace = TRUE, prob = probs)

  # For each chosen segment, sample from truncated exponential via inverse CDF
  samples <- numeric(n)
  for (i in 1:n) {
    j <- seg_choices[i]
    lo <- z[j]
    hi <- z[j + 1]
    u <- runif(1)

    if (abs(m[j]) < 1e-15) {
      if (!is.finite(lo)) lo <- hi - 20
      if (!is.finite(hi)) hi <- lo + 20
      samples[i] <- lo + u * (hi - lo)
    } else if (!is.finite(lo)) {
      # lo = -Inf, m > 0: inverse CDF gives x = hi + log(u) / m
      samples[i] <- hi + log(u) / m[j]
    } else if (!is.finite(hi)) {
      # hi = +Inf, m < 0: inverse CDF gives x = lo + log(u) / m (m < 0)
      samples[i] <- lo + log(u) / m[j]
    } else {
      log_lo <- m[j] * lo
      log_hi <- m[j] * hi
      log_max <- max(log_lo, log_hi)
      exp_lo <- exp(log_lo - log_max)
      exp_hi <- exp(log_hi - log_max)
      val <- exp_lo + u * (exp_hi - exp_lo)
      if (val <= 0) val <- 1e-300
      samples[i] <- (log_max + log(val)) / m[j]
    }
  }
  return(samples)
}

#' Choose initial abscissae for the ARS algorithm
#' @param lb lower bound
#' @param ub upper bound
#' @param f density function
#' @return vector of initial abscissae (at least 3, with required slope conditions)
choose_initial_abscissae <- function(lb, ub, f) {
  # Generate candidate points
  if (is.finite(lb) && is.finite(ub)) {
    margin <- (ub - lb) * 0.02
    pts <- seq(lb + margin, ub - margin, length.out = 20)
  } else if (is.finite(lb) && !is.finite(ub)) {
    pts <- lb + c(0.01, 0.05, 0.1, 0.2, 0.5, 1, 2, 3, 5, 8, 12, 18, 25, 40, 60)
  } else if (!is.finite(lb) && is.finite(ub)) {
    pts <- ub - c(0.01, 0.05, 0.1, 0.2, 0.5, 1, 2, 3, 5, 8, 12, 18, 25, 40, 60)
    pts <- sort(pts)
  } else {
    pts <- seq(-5, 5, length.out = 21)
  }

  pts <- sort(unique(pts))

  # Keep only points with positive density
  vals <- f(pts)
  good <- which(vals > 0 & !is.na(vals) & is.finite(vals))
  if (length(good) < 3) {
    stop("Cannot find at least 3 initial abscissae with positive density. Check domain bounds.")
  }
  pts <- pts[good]
  h <- log(vals[good])

  # For infinite left bound: trim until first secant slope > 0
  if (!is.finite(lb)) {
    while (length(pts) > 3) {
      s1 <- (h[2] - h[1]) / (pts[2] - pts[1])
      if (s1 > 1e-12) break
      pts <- pts[-1]; h <- h[-1]
    }
    if ((h[2] - h[1]) / (pts[2] - pts[1]) <= 0) {
      stop("Cannot find initial points where log-density is increasing from the left. Check domain.")
    }
  }

  # For infinite right bound: trim until last secant slope < 0
  if (!is.finite(ub)) {
    while (length(pts) > 3) {
      k <- length(pts)
      sk <- (h[k] - h[k-1]) / (pts[k] - pts[k-1])
      if (sk < -1e-12) break
      pts <- pts[-k]; h <- h[-k]
    }
    k <- length(pts)
    if ((h[k] - h[k-1]) / (pts[k] - pts[k-1]) >= 0) {
      stop("Cannot find initial points where log-density is decreasing on the right. Check domain.")
    }
  }

  if (length(pts) < 3) {
    stop("Cannot find suitable initial abscissae.")
  }

  # Subsample to avoid too many initial points (keep ~5-8)
  if (length(pts) > 8) {
    idx <- round(seq(1, length(pts), length.out = 8))
    # But always keep first and last
    idx <- sort(unique(c(1, idx, length(pts))))
    pts <- pts[idx]
  }

  return(pts)
}

#' Validate inputs to the ars function
validate_inputs <- function(f, n, lb, ub) {
  if (!is.function(f)) {
    stop("'f' must be a function.")
  }
  if (!is.numeric(n) || length(n) != 1 || n < 1 || n != as.integer(n)) {
    stop("'n' must be a positive integer.")
  }
  if (!is.numeric(lb) || length(lb) != 1) {
    stop("'lb' must be a single numeric value.")
  }
  if (!is.numeric(ub) || length(ub) != 1) {
    stop("'ub' must be a single numeric value.")
  }
  if (lb >= ub) {
    stop("Lower bound must be strictly less than upper bound.")
  }
}

# --- Main ARS Function ---

#' Adaptive Rejection Sampling
#'
#' @param f density function (possibly unnormalized), must be log-concave.
#' @param support optional 2-element vector c(lb, ub) for the domain
#' @param n number of samples to generate (default 100)
#' @param lb lower bound of the domain (default -Inf)
#' @param ub upper bound of the domain (default Inf)
#' @param ... additional arguments (currently unused)
#' @return vector of n samples from the target distribution
ars <- function(f, support = NULL, n = 100, lb = -Inf, ub = Inf, ...) {
  # Handle the support vector argument
  if (!is.null(support) && is.numeric(support) && length(support) == 2) {
    lb <- support[1]
    ub <- support[2]
  }

  validate_inputs(f, n, lb, ub)

  abscissae <- choose_initial_abscissae(lb, ub, f)
  h_vals <- eval_log_density(f, abscissae)
  check_log_concavity(abscissae, h_vals)

  samples <- numeric(n)
  count <- 0
  max_iter <- n * 200
  iter <- 0

  while (count < n && iter < max_iter) {
    iter <- iter + 1

    hull <- compute_upper_hull(abscissae, h_vals, lb, ub)
    x_star <- sample_upper_hull(1, hull)

    u <- runif(1)
    u_val <- eval_upper_hull(x_star, hull)
    l_val <- eval_lower_hull(x_star, abscissae, h_vals)

    if (u <= exp(l_val - u_val)) {
      count <- count + 1
      samples[count] <- x_star
    } else {
      h_star <- eval_log_density(f, x_star)

      if (u <= exp(h_star - u_val)) {
        count <- count + 1
        samples[count] <- x_star
      }

      # Add new point to abscissae
      insert_pos <- findInterval(x_star, abscissae) + 1
      abscissae <- append(abscissae, x_star, after = insert_pos - 1)
      h_vals <- append(h_vals, h_star, after = insert_pos - 1)

      check_log_concavity(abscissae, h_vals)
    }
  }

  if (count < n) {
    warning(paste("Only generated", count, "out of", n, "requested samples."))
  }

  return(samples)
}

# --- Test Function ---

#' Run formal tests of the ARS implementation
test <- function() {
  cat("============================================================\n")
  cat("     Adaptive Rejection Sampling (ARS) - Test Suite\n")
  cat("============================================================\n\n")

  pass_count <- 0
  fail_count <- 0

  run_test <- function(name, expr) {
    result <- tryCatch(expr, error = function(e) {
      cat(paste0("  Error: ", e$message, "\n"))
      return(FALSE)
    })
    if (isTRUE(result)) {
      cat(paste0(name, ": PASS\n\n"))
      pass_count <<- pass_count + 1
    } else {
      cat(paste0(name, ": FAIL\n\n"))
      fail_count <<- fail_count + 1
    }
  }

  # ---- Input Validation Tests ----
  cat("--- Input Validation Tests ---\n\n")

  run_test("test_negative_n", {
    cat("  Testing that negative n is rejected...\n")
    tryCatch({ ars(dnorm, n = -5); FALSE },
             error = function(e) grepl("positive integer", e$message))
  })

  run_test("test_zero_n", {
    cat("  Testing that n=0 is rejected...\n")
    tryCatch({ ars(dnorm, n = 0); FALSE },
             error = function(e) grepl("positive integer", e$message))
  })

  run_test("test_non_integer_n", {
    cat("  Testing that non-integer n is rejected...\n")
    tryCatch({ ars(dnorm, n = 3.5); FALSE },
             error = function(e) grepl("positive integer", e$message))
  })

  run_test("test_invalid_bounds", {
    cat("  Testing that lb >= ub is rejected...\n")
    tryCatch({ ars(dnorm, n = 10, lb = 5, ub = 2); FALSE },
             error = function(e) grepl("strictly less", e$message))
  })

  run_test("test_non_function_f", {
    cat("  Testing that non-function f is rejected...\n")
    tryCatch({ ars("not_a_function", n = 10); FALSE },
             error = function(e) grepl("must be a function", e$message))
  })

  # ---- Log-Concavity Tests ----
  cat("--- Log-Concavity Tests ---\n\n")

  run_test("test_bimodal_rejection", {
    cat("  Testing rejection of bimodal (non-log-concave) density...\n")
    bimodal <- function(x) 0.5 * dnorm(x, -3, 0.5) + 0.5 * dnorm(x, 3, 0.5)
    tryCatch({ ars(bimodal, n = 1000, lb = -10, ub = 10); FALSE },
             error = function(e) grepl("[Ll]og-concav", e$message))
  })

  run_test("test_cauchy_rejection", {
    cat("  Testing rejection of Cauchy (non-log-concave) density...\n")
    tryCatch({ ars(dcauchy, n = 1000, lb = -100, ub = 100); FALSE },
             error = function(e) grepl("[Ll]og-concav", e$message))
  })

  # ---- Module-Level Tests ----
  cat("--- Module-Level Tests ---\n\n")

  run_test("test_eval_log_density", {
    cat("  Testing eval_log_density with dnorm...\n")
    result <- eval_log_density(dnorm, 0)
    expected <- log(dnorm(0))
    cat(paste0("  log(dnorm(0)) = ", round(result, 6),
               " (expected ", round(expected, 6), ")\n"))
    abs(result - expected) < 1e-10
  })

  run_test("test_check_log_concavity_valid", {
    cat("  Testing log-concavity check on concave data...\n")
    x <- c(-2, -1, 0, 1, 2)
    h <- -x^2
    tryCatch({ check_log_concavity(x, h); TRUE }, error = function(e) FALSE)
  })

  run_test("test_check_log_concavity_invalid", {
    cat("  Testing log-concavity check on convex data...\n")
    x <- c(-2, -1, 0, 1, 2)
    h <- x^2
    tryCatch({ check_log_concavity(x, h); FALSE },
             error = function(e) grepl("[Ll]og-concav", e$message))
  })

  run_test("test_upper_hull_above_density", {
    cat("  Testing that upper hull >= log-density at test points...\n")
    x_abs <- c(-3, -1, 0, 1, 3)
    h_abs <- eval_log_density(dnorm, x_abs)
    hull <- compute_upper_hull(x_abs, h_abs, -Inf, Inf)
    test_pts <- seq(-2.5, 2.5, by = 0.1)
    h_test <- eval_log_density(dnorm, test_pts)
    u_test <- eval_upper_hull(test_pts, hull)
    all_above <- all(u_test >= h_test - 1e-6)
    cat(paste0("  Upper hull >= log-density at all ", length(test_pts),
               " test points: ", all_above, "\n"))
    all_above
  })

  run_test("test_lower_hull_below_density", {
    cat("  Testing that lower hull <= log-density at test points...\n")
    x_abs <- c(-3, -1, 0, 1, 3)
    h_abs <- eval_log_density(dnorm, x_abs)
    test_pts <- seq(-2.5, 2.5, by = 0.1)
    h_test <- eval_log_density(dnorm, test_pts)
    l_test <- sapply(test_pts, function(x) eval_lower_hull(x, x_abs, h_abs))
    all_below <- all(l_test <= h_test + 1e-6)
    cat(paste0("  Lower hull <= log-density at all ", length(test_pts),
               " test points: ", all_below, "\n"))
    all_below
  })

  # ---- Sampling Tests: Standard Normal ----
  cat("--- Standard Normal Distribution Tests ---\n\n")

  run_test("test_normal_unbounded", {
    cat("  Sampling 5000 points from N(0,1) on (-Inf, Inf)...\n")
    set.seed(42)
    samples <- ars(n = 5000, f = dnorm, lb = -Inf, ub = Inf)
    m <- mean(samples); s <- sd(samples)
    cat(paste0("  Sample mean: ", round(m, 4), " (expected ~0)\n"))
    cat(paste0("  Sample sd:   ", round(s, 4), " (expected ~1)\n"))
    writeLines(as.character(samples), "/app/normal_samples.txt")
    cat("  Saved samples to /app/normal_samples.txt\n")
    ks <- ks.test(samples, "pnorm")
    cat(paste0("  KS test p-value: ", round(ks$p.value, 4), "\n"))
    abs(m) < 0.15 && abs(s - 1) < 0.15 && ks$p.value > 0.01
  })

  run_test("test_normal_bounded", {
    cat("  Sampling 2000 points from N(0,1) on [-5, 5]...\n")
    set.seed(123)
    samples <- ars(dnorm, c(-5, 5), n = 2000)
    m <- mean(samples); s <- sd(samples)
    cat(paste0("  Sample mean: ", round(m, 4), "\n"))
    cat(paste0("  Sample sd:   ", round(s, 4), "\n"))
    cat(paste0("  Range: [", round(min(samples), 4), ", ", round(max(samples), 4), "]\n"))
    all(samples >= -5 & samples <= 5) && abs(m) < 0.2
  })

  run_test("test_normal_shifted", {
    cat("  Sampling 3000 points from N(5, 2^2) on (-Inf, Inf)...\n")
    set.seed(200)
    shifted_norm <- function(x) dnorm(x, mean = 5, sd = 2)
    samples <- ars(shifted_norm, n = 3000, lb = -Inf, ub = Inf)
    m <- mean(samples); s <- sd(samples)
    cat(paste0("  Sample mean: ", round(m, 4), " (expected ~5)\n"))
    cat(paste0("  Sample sd:   ", round(s, 4), " (expected ~2)\n"))
    ks <- ks.test(samples, "pnorm", mean = 5, sd = 2)
    cat(paste0("  KS test p-value: ", round(ks$p.value, 4), "\n"))
    abs(m - 5) < 0.3 && abs(s - 2) < 0.3 && ks$p.value > 0.01
  })

  # ---- Sampling Tests: Exponential ----
  cat("--- Exponential Distribution Tests ---\n\n")

  run_test("test_exponential_sampling", {
    cat("  Sampling 5000 points from Exp(1) on [0.001, 50]...\n")
    set.seed(99)
    samples <- ars(dexp, c(0.001, 50), n = 5000)
    m <- mean(samples); s <- sd(samples)
    cat(paste0("  Sample mean: ", round(m, 4), " (expected ~1)\n"))
    cat(paste0("  Sample sd:   ", round(s, 4), " (expected ~1)\n"))
    writeLines(as.character(samples), "/app/exponential_samples.txt")
    cat("  Saved samples to /app/exponential_samples.txt\n")
    ks <- ks.test(samples, "pexp")
    cat(paste0("  KS test p-value: ", round(ks$p.value, 4), "\n"))
    abs(m - 1) < 0.2 && ks$p.value > 0.01
  })

  # ---- Sampling Tests: Gamma ----
  cat("--- Gamma Distribution Tests ---\n\n")

  run_test("test_gamma_sampling", {
    cat("  Sampling 3000 points from Gamma(3, 1) on [0.01, 30]...\n")
    set.seed(77)
    gamma_dens <- function(x) dgamma(x, shape = 3, rate = 1)
    samples <- ars(gamma_dens, c(0.01, 30), n = 3000)
    m <- mean(samples); s <- sd(samples)
    cat(paste0("  Sample mean: ", round(m, 4), " (expected ~3)\n"))
    cat(paste0("  Sample sd:   ", round(s, 4), " (expected ~1.73)\n"))
    ks <- ks.test(samples, "pgamma", shape = 3, rate = 1)
    cat(paste0("  KS test p-value: ", round(ks$p.value, 4), "\n"))
    abs(m - 3) < 0.4 && ks$p.value > 0.01
  })

  # ---- Sampling Tests: Beta ----
  cat("--- Beta Distribution Tests ---\n\n")

  run_test("test_beta_sampling", {
    cat("  Sampling 3000 points from Beta(2, 5) on [0.01, 0.99]...\n")
    set.seed(55)
    beta_dens <- function(x) dbeta(x, shape1 = 2, shape2 = 5)
    samples <- ars(beta_dens, c(0.01, 0.99), n = 3000)
    expected_mean <- 2 / (2 + 5)
    expected_sd <- sqrt(2 * 5 / ((2 + 5)^2 * (2 + 5 + 1)))
    m <- mean(samples); s <- sd(samples)
    cat(paste0("  Sample mean: ", round(m, 4),
               " (expected ~", round(expected_mean, 4), ")\n"))
    cat(paste0("  Sample sd:   ", round(s, 4),
               " (expected ~", round(expected_sd, 4), ")\n"))
    ks <- ks.test(samples, "pbeta", shape1 = 2, shape2 = 5)
    cat(paste0("  KS test p-value: ", round(ks$p.value, 4), "\n"))
    abs(m - expected_mean) < 0.05 && ks$p.value > 0.01
  })

  # ---- Sampling Tests: Unnormalized density ----
  cat("--- Unnormalized Density Test ---\n\n")

  run_test("test_unnormalized_density", {
    cat("  Sampling from unnormalized Gaussian: f(x) = exp(-x^2/2)...\n")
    set.seed(33)
    unnorm_gauss <- function(x) exp(-x^2 / 2)
    samples <- ars(unnorm_gauss, n = 3000, lb = -Inf, ub = Inf)
    m <- mean(samples); s <- sd(samples)
    cat(paste0("  Sample mean: ", round(m, 4), " (expected ~0)\n"))
    cat(paste0("  Sample sd:   ", round(s, 4), " (expected ~1)\n"))
    ks <- ks.test(samples, "pnorm")
    cat(paste0("  KS test p-value: ", round(ks$p.value, 4), "\n"))
    abs(m) < 0.15 && abs(s - 1) < 0.15 && ks$p.value > 0.01
  })

  # ---- Summary ----
  cat("============================================================\n")
  total <- pass_count + fail_count
  cat(paste0("  TOTAL: ", total, " tests, ",
             pass_count, " passed, ", fail_count, " failed\n"))
  cat("============================================================\n")

  invisible(list(passed = pass_count, failed = fail_count))
}

